import React from 'react';
import { motion } from 'framer-motion';

const Logo: React.FC<{ size?: 'small' | 'medium' | 'large' }> = ({ size = 'medium' }) => {
  const sizeClasses = {
    small: 'w-8 h-8',
    medium: 'w-12 h-12',
    large: 'w-24 h-24'
  };

  return (
    <div className={`relative ${sizeClasses[size]}`}>
      <div className="w-full h-full bg-gradient-to-r from-[#5b3e31] to-[#3d3b3a] rounded-full flex items-center justify-center">
        <span className="text-white font-bold text-xs md:text-sm lg:text-lg">MM</span>
      </div>
    </div>
  );
};

export default Logo;
